ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/construction#>
PREFIX p: <http://ambrosia.example.org/construction/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?name ?seating_capacity ?maximum_occupancy WHERE {
  ?stadiums a :Stadiums .
  ?stadiums p:name ?name .
  ?stadiums p:Seating_Capacity ?seating_capacity .
  ?stadiums p:Maximum_Occupancy ?maximum_occupancy .
} }
  component: { SELECT ?name ?maximum_occupancy WHERE {
  ?stadiums a :Stadiums .
  ?stadiums p:name ?name .
  ?stadiums p:Maximum_Occupancy ?maximum_occupancy .
} }
  component_2: { SELECT ?name ?seating_capacity WHERE {
  ?stadiums a :Stadiums .
  ?stadiums p:name ?name .
  ?stadiums p:Seating_Capacity ?seating_capacity .
} }
}
